#include<bits/stdc++.h>
using namespace std;
struct node{
    int x,y,z;
}e[4000005];
int n,m;
int s[200005];
int sfind(int x) {
	if (x == s[x])	return x;
	else return s[x] = sfind(s[x]);
}
bool smerge(int i, int x) {
	int fi = sfind(i);
	int fx = sfind(x);
	if (fi == fx) {
		return false;
	}
    s[fx] = fi;
    return true;
}
bool cmp(node a,node b){
    return a.z>b.z;
}
int main() {
	cin>>n;
    int a[2005];
    for(int i=1;i<=n;i++) {
        cin>>a[i];
        s[i]=i;

    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            e[(i-1)*n+j].x=i;
            e[(i-1)*n+j].y=j;
            e[(i-1)*n+j].z=a[i]^a[j];
        }
    }
    sort(e+1,e+1+n*n,cmp);
    long long ans=0,ans2=0;
    for(int i=1;i<=n*n;i++){
		if(smerge(e[i].x,e[i].y)){
            ans+=e[i].z;
            ans2+=1;
        }
	}
    if(ans2!=n-1) cout<<"orz";
    else cout<<ans;
	return 0;
}
